#include <stdio.h>
#include <string.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char s[100005];
        scanf("%s", s);
        if (strstr(s, "010") != NULL || strstr(s, "101") != NULL) {
            printf("Good\n");
        } else {
            printf("Bad\n");
        }
    }
    return 0;
}

code.C++:
#include <iostream>
#include <string>
using namespace std;
int main() {
    ios::sync_with_stdio(false);
    cin.tie(NULL);
    int T;
    cin >> T;
    while (T--) {
        string s;
        cin >> s;
        if (s.find("010") != string::npos || s.find("101") != string::npos) {
            cout << "Good" << endl;
        } else {
            cout << "Bad" << endl;
        }
    }
    return 0;
}

